@pytest.fixture
def frozen_clock():
    with freeze_time("2026-01-01T00:00:00Z"):
        yield

@pytest.fixture
def seeded_rng(request):
    seed = hash(request.node.name) & 0xFFFFFFFF
    random.seed(seed); np.random.seed(seed)
    yield seed

def test_invoice_due_date(frozen_clock, seeded_rng, invoice_factory):
    inv = invoice_factory(amount=100)
    assert inv.due_at == datetime(2026, 1, 31, tzinfo=UTC)
